 472→int Parameters::load(string filename) {
 473→  FILE *fh;
 474→
 475→  fh = fopen(filename.c_str(), "rb");
 476→  if (fh == NULL) {
 477→    fprintf(stderr, "error: %s\n", strerror(errno));
 478→    return 1;
 479→  }
 480→  int error = load(fh);
 481→  fclose(fh);
 482→  return error;
 483→}
